54	// DecideAttemptTransition implements the ddx try retry state machine for one
55	// attempt result. The default bias is forward progress: semantic failures move
56	// up the model-power ladder, while retryable provider-connectivity failures can
57	// be retried immediately with MinPower set just above the failed route's actual
58	// power. Infrastructure failures without concrete route evidence still stop the
59	// current attempt; a smarter model cannot fix an absent service with no
60	// alternate power signal.
61	func DecideAttemptTransition(input AttemptTransitionInput, ladder FloorFinder) AttemptTransition {
62		if input.Disrupted {
63			return stopTransition("disrupted")
64		}
65		if input.BudgetExhausted {
66			return stopTransition("budget_exhausted")
67		}
68		if !escalation.ShouldEscalate(input.Status) {
