77			if next <= input.CurrentMinPower {
78				next = input.CurrentMinPower + 1
79			}
80			return AttemptTransition{
81				State:        TryLoopStateRetryPower,
82				Action:       TryLoopActionRetryPower,
83				NextMinPower: next,
84				Reason:       "infrastructure_retry_with_higher_min_power",
85			}
86		}
87	
88		basis := input.CurrentMinPower
89		if input.ActualPower > 0 {
