package agent

import "strings"

// OutcomeClass is the high-level classification of an attempt outcome per the
// FEAT-004 addendum failure-classification table. Each class maps to exactly
// one OutcomeAction the drain loop must apply.
type OutcomeClass string

const (
	// OutcomeClassSuccess covers merged / task_succeeded outcomes.
	OutcomeClassSuccess OutcomeClass = "success"
	// OutcomeClassAlreadySatisfied is a sub-case of success: no work was needed.
	OutcomeClassAlreadySatisfied OutcomeClass = "already_satisfied"
	// OutcomeClassNoChanges covers no_changes outcomes. Never triggers tier escalation.
	OutcomeClassNoChanges OutcomeClass = "no_changes"
	// OutcomeClassGenuineFailure covers implementation/capability failures that
	// justify one middle→max tier escalation. Examples: test_failure, build_failure.
	OutcomeClassGenuineFailure OutcomeClass = "genuine_failure"
	// OutcomeClassMaxGenuineFailure is a genuine failure at the max power tier:
	// escalation is exhausted and the bead requires operator attention.
	OutcomeClassMaxGenuineFailure OutcomeClass = "max_genuine_failure"
	// OutcomeClassDirty is a dirty-repo failure: the working tree had uncommitted
	// changes. Action: clean and retry at the same tier (no power escalation).
	OutcomeClassDirty OutcomeClass = "dirty"
	// OutcomeClassTransport is a provider-connectivity or routing failure that is
	// not the model's fault. Action: reroute at the same tier (no power escalation).
	OutcomeClassTransport OutcomeClass = "transport"
	// OutcomeClassQuotaExhausted is a rate-limit or quota-exhaustion failure.
	// Action: apply a global pool cooldown (not per-bead mutations).
	OutcomeClassQuotaExhausted OutcomeClass = "quota_exhausted"
	// OutcomeClassAuthSetup covers authentication failures and harness setup
	// problems that require operator attention to fix.
	OutcomeClassAuthSetup OutcomeClass = "auth_setup"
	// OutcomeClassTimeout covers execution timeouts and watchdog termination.
	// Action: clean and retry once, then escalate to operator attention.
	OutcomeClassTimeout OutcomeClass = "timeout"
	// OutcomeClassMergeConflict covers land conflicts. Action: unclaim and retry.
	OutcomeClassMergeConflict OutcomeClass = "merge_conflict"
)

// OutcomeAction is the action the drain loop must apply for a classified outcome.
type OutcomeAction string

const (
	// OutcomeActionClose closes the bead (success / already_satisfied).
	OutcomeActionClose OutcomeAction = "close"
	// OutcomeActionCloseUnclaim closes or unclims the bead for no_changes.
	// No tier escalation is applied.
	OutcomeActionCloseUnclaim OutcomeAction = "close_unclaim"
	// OutcomeActionEscalateOnce triggers a single middle→max tier escalation.
	// Only for the first genuine failure; a second genuine failure at the top
	// tier routes to OutcomeActionOperatorAttention instead.
	OutcomeActionEscalateOnce OutcomeAction = "escalate_once"
	// OutcomeActionOperatorAttention routes the bead to operator attention
	// (status=proposed). Used for max-tier genuine failures, auth/setup errors,
	// and conditions an automated retry cannot resolve.
	OutcomeActionOperatorAttention OutcomeAction = "operator_attention"
	// OutcomeActionCleanSameTierRetry cleans the working tree and retries the
	// bead at the same power tier (dirty-repo recovery).
	OutcomeActionCleanSameTierRetry OutcomeAction = "clean_same_tier_retry"
	// OutcomeActionSameTierReroute retries at the same power tier via a different
	// route (transport/connectivity recovery).
	OutcomeActionSameTierReroute OutcomeAction = "same_tier_reroute"
	// OutcomeActionGlobalPoolCooldown pauses the entire worker pool until quota
	// recovers. Not a per-bead mutation: the bead is unclaimed without cooldown
	// while the pool-level pause is active.
	OutcomeActionGlobalPoolCooldown OutcomeAction = "global_pool_cooldown"
	// OutcomeActionCleanRetryThenOperator retries once after a timeout, then
	// routes to operator attention if the timeout recurs.
	OutcomeActionCleanRetryThenOperator OutcomeAction = "clean_retry_then_operator"
	// OutcomeActionUnclaimRetry unclims the bead and re-queues it for another
	// attempt (merge-conflict recovery).
	OutcomeActionUnclaimRetry OutcomeAction = "unclaim_retry"
)

// ClassifyOutcomeAction maps an attempt result to an OutcomeClass and the
// corresponding OutcomeAction per the FEAT-004 addendum failure-classification
// table. Callers supply:
//   - status: the ExecuteBeadStatus* string from the attempt report
//   - failureMode: the FailureMode* string (may be empty)
//   - detail: the free-text detail/error string for secondary disambiguation
//   - atMaxTier: true when the attempt ran at the maximum available power tier
//
// The mapping is pure and deterministic. No_changes, dirty, transport, quota,
// and auth outcomes never trigger tier escalation regardless of atMaxTier.
func ClassifyOutcomeAction(status, failureMode, detail string, atMaxTier bool) (OutcomeClass, OutcomeAction) {
	// Terminal success outcomes.
	switch status {
	case ExecuteBeadStatusSuccess:
		return OutcomeClassSuccess, OutcomeActionClose
	case ExecuteBeadStatusAlreadySatisfied:
		return OutcomeClassAlreadySatisfied, OutcomeActionClose
	case ExecuteBeadStatusNoChanges:
		return OutcomeClassNoChanges, OutcomeActionCloseUnclaim
	case ExecuteBeadStatusLandConflict,
		ExecuteBeadStatusLandConflictUnresolvable,
		ExecuteBeadStatusLandConflictOperatorRequired:
		return OutcomeClassMergeConflict, OutcomeActionUnclaimRetry
	}

	// Failure-mode–driven classification. These are ordered so that the most
	// specific failure modes are checked first; the genuine-failure fallback at
	// the bottom only fires when no earlier case matches.
	switch failureMode {
	case FailureModeDirtyRepo:
		return OutcomeClassDirty, OutcomeActionCleanSameTierRetry
	case FailureModeNoChanges, FailureModeNoEvidenceProduced:
		return OutcomeClassNoChanges, OutcomeActionCloseUnclaim
	case FailureModeMergeConflict:
		return OutcomeClassMergeConflict, OutcomeActionUnclaimRetry
	case FailureModeProviderConnectivity,
		FailureModeNoViableProvider,
		FailureModeBlockedByPassthroughConstraint,
		FailureModeAgentPowerUnsatisfied:
		return OutcomeClassTransport, OutcomeActionSameTierReroute
	case FailureModeAuthError:
		if isQuotaExhaustedDetail(detail) {
			return OutcomeClassQuotaExhausted, OutcomeActionGlobalPoolCooldown
		}
		return OutcomeClassAuthSetup, OutcomeActionOperatorAttention
	case FailureModeHarnessNotInstalled:
		return OutcomeClassAuthSetup, OutcomeActionOperatorAttention
	case FailureModeTimeout,
		FailureModeProgressWatchdog,
		FailureModeRouteResolutionTimeout,
		FailureModeConsecutiveWedge:
		return OutcomeClassTimeout, OutcomeActionCleanRetryThenOperator
	}

	// Genuine implementation/capability failure: test_failure, build_failure,
	// context_overflow, ratchet_miss, unknown, etc. — and any unclassified
	// escalatable status. A smarter model may succeed where the current one failed.
	if atMaxTier {
		return OutcomeClassMaxGenuineFailure, OutcomeActionOperatorAttention
	}
	return OutcomeClassGenuineFailure, OutcomeActionEscalateOnce
}

// isQuotaExhaustedDetail reports whether the detail string indicates a
// rate-limit or quota-exhaustion condition, as opposed to an invalid-credentials
// auth error. Both are classified as FailureModeAuthError by ClassifyFailureMode
// but require different drain-loop actions (pool cooldown vs operator attention).
func isQuotaExhaustedDetail(detail string) bool {
	lower := strings.ToLower(detail)
	return containsAny(lower,
		"429",
		"rate limit",
		"ratelimit",
		"rate_limit",
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"too many requests",
	)
}

package agent

import (
	"sync"
	"sync/atomic"
	"time"
)

// PoolInFlightCap limits the number of concurrent escalated attempts within a
// single worker pool. The cap prevents multi-worker stampedes where every worker
// independently escalates a genuine failure to the max tier at the same time.
//
// Usage: before escalating a genuine failure, call TryAcquire. If it returns
// false, do not escalate; treat the attempt as a same-tier failure instead.
// Call Release when the escalated attempt finishes (success or failure).
//
// A zero-value PoolInFlightCap is not valid; use NewPoolInFlightCap.
type PoolInFlightCap struct {
	max     int32
	current atomic.Int32
}

// NewPoolInFlightCap constructs a cap that allows at most max concurrent
// in-flight escalations. max <= 0 disables the cap (TryAcquire always returns
// true).
func NewPoolInFlightCap(max int) *PoolInFlightCap {
	return &PoolInFlightCap{max: int32(max)}
}

// TryAcquire attempts to reserve one in-flight slot. Returns true when a slot
// was acquired (the caller may proceed with escalation) and false when the cap
// is full (the caller should not escalate this attempt).
func (c *PoolInFlightCap) TryAcquire() bool {
	if c.max <= 0 {
		return true
	}
	for {
		cur := c.current.Load()
		if cur >= c.max {
			return false
		}
		if c.current.CompareAndSwap(cur, cur+1) {
			return true
		}
	}
}

// Release returns one in-flight slot acquired via TryAcquire. Callers MUST
// call Release exactly once for each successful TryAcquire.
func (c *PoolInFlightCap) Release() {
	c.current.Add(-1)
}

// InFlight returns the current number of in-flight escalations.
func (c *PoolInFlightCap) InFlight() int {
	return int(c.current.Load())
}

// PoolCooldown tracks a global pool-level pause for quota exhaustion. When
// active, workers should stop claiming new beads until the cooldown expires.
// It replaces per-bead retry-after mutations: a single PoolCooldown.Set call
// covers all beads in the pool without touching each bead record individually.
//
// Safe for concurrent use.
type PoolCooldown struct {
	mu     sync.Mutex
	until  time.Time
	reason string
}

// Set records a pool-level pause until the given time. If the new until is
// earlier than the existing until, the call is a no-op (the later deadline wins).
func (p *PoolCooldown) Set(until time.Time, reason string) {
	p.mu.Lock()
	defer p.mu.Unlock()
	if until.After(p.until) {
		p.until = until
		p.reason = reason
	}
}

// Active reports whether the pool cooldown is currently in effect at the given
// wall-clock time. Returns (true, resumeAt, reason) when active, or
// (false, zero, "") when the cooldown has expired or was never set.
func (p *PoolCooldown) Active(now time.Time) (bool, time.Time, string) {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.until.IsZero() || !now.Before(p.until) {
		return false, time.Time{}, ""
	}
	return true, p.until, p.reason
}

