// TestClassifyOutcomeAction_NoEscalateForNonGenuine verifies that the non-genuine
// outcome classes never return OutcomeActionEscalateOnce regardless of atMaxTier
// (AC2: no_changes/dirty/transport/quota/auth do NOT escalate).
func TestClassifyOutcomeAction_NoEscalateForNonGenuine(t *testing.T) {
	nonEscalatable := []struct {
		status      string
		failureMode string
		detail      string
	}{
		// no_changes
		{status: ExecuteBeadStatusNoChanges},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeNoChanges},
		// dirty
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeDirtyRepo},
		// transport
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeProviderConnectivity},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeNoViableProvider},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeBlockedByPassthroughConstraint},
		// quota
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeAuthError, detail: "429 rate limit"},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeAuthError, detail: "quota exceeded"},
		// auth/setup
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeAuthError, detail: "401 unauthorized"},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeHarnessNotInstalled},
		// timeout
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeTimeout},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeProgressWatchdog},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeRouteResolutionTimeout},
		// merge-conflict
		{status: ExecuteBeadStatusLandConflict},
		{status: ExecuteBeadStatusExecutionFailed, failureMode: FailureModeMergeConflict},
	}
	for _, c := range nonEscalatable {
		for _, atMax := range []bool{false, true} {
			_, action := ClassifyOutcomeAction(c.status, c.failureMode, c.detail, atMax)
			assert.NotEqualf(t, OutcomeActionEscalateOnce, action,
				"status=%q failureMode=%q detail=%q atMaxTier=%v must not escalate",
				c.status, c.failureMode, c.detail, atMax)
		}
	}
}

// TestClassifyOutcomeAction_GenuineFailureEscalatesOnlyOnce verifies that a
// genuine failure at middle tier returns EscalateOnce, and the same failure at
// max tier returns OperatorAttention (one-hop middle→max, then stop) (AC2).
func TestClassifyOutcomeAction_GenuineFailureEscalatesOnlyOnce(t *testing.T) {
