// TestPoolInFlightCap_EnforcesMaxConcurrent tests that PoolInFlightCap refuses
// acquisition beyond the configured cap (AC3).
func TestPoolInFlightCap_EnforcesMaxConcurrent(t *testing.T) {
	const maxConcurrent = 3
	cap := NewPoolInFlightCap(maxConcurrent)

	// Acquire up to the limit
	for i := 0; i < maxConcurrent; i++ {
		assert.Truef(t, cap.TryAcquire(), "acquire %d of %d should succeed", i+1, maxConcurrent)
	}
	assert.Equal(t, maxConcurrent, cap.InFlight(), "should be at cap")

	// One more should fail
	assert.False(t, cap.TryAcquire(), "acquire beyond cap should fail")

	// Release one slot, then re-acquire
	cap.Release()
	assert.Equal(t, maxConcurrent-1, cap.InFlight(), "should be one below cap after release")
	assert.True(t, cap.TryAcquire(), "acquire after release should succeed")

	// Still at cap
	assert.False(t, cap.TryAcquire(), "should still be at cap after re-acquire")
}

// TestPoolInFlightCap_ConcurrentGenuineFailures simulates multiple workers
// hitting genuine failures concurrently and asserts the cap is respected (AC3).
func TestPoolInFlightCap_ConcurrentGenuineFailures(t *testing.T) {
	const maxConcurrent = 5
	const numWorkers = 30
	cap := NewPoolInFlightCap(maxConcurrent)

	var inFlight atomic.Int32
	var peakInFlight atomic.Int32
	var wg sync.WaitGroup

	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			if cap.TryAcquire() {
				// Record peak in-flight.
				cur := inFlight.Add(1)
				for {
					old := peakInFlight.Load()
					if cur <= old {
						break
					}
					if peakInFlight.CompareAndSwap(old, cur) {
						break
					}
				}
				// Simulate work.
				time.Sleep(time.Millisecond)
				inFlight.Add(-1)
				cap.Release()
			}
		}()
	}
	wg.Wait()

	peak := int(peakInFlight.Load())
	assert.LessOrEqualf(t, peak, maxConcurrent,
		"peak concurrent in-flight escalations (%d) must not exceed cap (%d)",
		peak, maxConcurrent)
}

// TestPoolInFlightCap_ZeroCapDisabled verifies that a zero cap disables the
// limit and always grants acquisition.
func TestPoolInFlightCap_ZeroCapDisabled(t *testing.T) {
	cap := NewPoolInFlightCap(0)
	for i := 0; i < 100; i++ {
		assert.True(t, cap.TryAcquire(), "unlimited cap should always grant")
	}
}

// TestQuotaExhaustedUsesGlobalPoolCooldown verifies that quota-exhausted outcomes
// classify as OutcomeActionGlobalPoolCooldown (not per-bead mutations), and that
// PoolCooldown tracks the pool-level pause correctly (AC4).
func TestQuotaExhaustedUsesGlobalPoolCooldown(t *testing.T) {
	// Classification must be global pool cooldown.
	class, action := ClassifyOutcomeAction(ExecuteBeadStatusExecutionFailed, FailureModeAuthError, "429 rate limit exceeded", false)
	assert.Equal(t, OutcomeClassQuotaExhausted, class, "quota must classify as quota_exhausted")
	assert.Equal(t, OutcomeActionGlobalPoolCooldown, action, "quota must trigger global pool cooldown")

	// Not a per-bead mutation.
	assert.NotEqual(t, OutcomeActionCleanRetryThenOperator, action, "quota must not be per-bead retry")
	assert.NotEqual(t, OutcomeActionUnclaimRetry, action, "quota must not be unclaim+retry")
	assert.NotEqual(t, OutcomeActionEscalateOnce, action, "quota must not escalate")

	// PoolCooldown tracks the single pool-level pause.
	cooldown := &PoolCooldown{}
	resumeAt := time.Now().Add(15 * time.Minute)
	cooldown.Set(resumeAt, "quota exhausted: 429 rate limit")

	active, until, reason := cooldown.Active(time.Now())
	assert.True(t, active, "pool cooldown should be active")
	assert.Equal(t, resumeAt, until, "resume time should match")
	assert.Contains(t, reason, "quota exhausted", "reason should describe the cause")

	// Cooldown expires after the resume time.
	active, _, _ = cooldown.Active(resumeAt.Add(time.Second))
	assert.False(t, active, "pool cooldown should expire after resume time")
}

// TestPoolCooldown_LaterDeadlineWins verifies that Set does not shorten an
// existing cooldown (the later deadline always wins).
func TestPoolCooldown_LaterDeadlineWins(t *testing.T) {
	cooldown := &PoolCooldown{}
	now := time.Now()

	// Set a 5-minute cooldown.
	cooldown.Set(now.Add(5*time.Minute), "first")
	// Attempt to shorten it to 2 minutes — should have no effect.
	cooldown.Set(now.Add(2*time.Minute), "shorter")
	// Extend it to 10 minutes — should take effect.
	cooldown.Set(now.Add(10*time.Minute), "longer")

	active, until, reason := cooldown.Active(now)
	assert.True(t, active)
	assert.Equal(t, now.Add(10*time.Minute), until, "later deadline must win")
	assert.Equal(t, "longer", reason, "reason should reflect the winning deadline")
}

// TestClassifyFailureMode_DirtyRepo verifies that ClassifyFailureMode returns
// FailureModeDirtyRepo for dirty-tree guard error messages.
func TestClassifyFailureMode_DirtyRepo(t *testing.T) {
	mode := ClassifyFailureMode(ExecuteBeadOutcomeTaskFailed, 1, "working tree is not clean; modified files:\nfoo.go")
	assert.Equal(t, FailureModeDirtyRepo, mode, "dirty-tree error must classify as dirty_repo")

	mode = ClassifyFailureMode(ExecuteBeadOutcomeTaskFailed, 1, "Working Tree Is Not Clean: bar.go")
	assert.Equal(t, FailureModeDirtyRepo, mode, "dirty-tree error must classify as dirty_repo (case-insensitive)")
}

